    @media #{layout.$medium-screen-and-smaller} {
        padding: 40px 32px;
    }

    @media #{layout.$small-screen-and-smaller} {
        padding: 32px 15px;
        overflow-x: auto;
    }

    &__items {
        display: flex;
        gap: 24px;

        @media #{layout.$small-screen-and-smaller} {
            // Horizontal scroll on mobile
            flex-wrap: nowrap;
            min-width: max-content;
        }
    }

    &__item {
        flex: 1;
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 16px;
